import{_ as a,o as i,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Carrier Services","description":"Shopify carrier-calculated shipping rates via app callback URL.","frontmatter":{"title":"Carrier Services","description":"Shopify carrier-calculated shipping rates via app callback URL."},"headers":[],"relativePath":"software-engineering/shopify-dev/carrier-services.md","filePath":"software-engineering/shopify-dev/carrier-services.md"}'),t={name:"software-engineering/shopify-dev/carrier-services.md"};function o(c,e,l,n,h,p){return i(),r("div",null,[...e[0]||(e[0]=[s(`<h1 id="carrier-services" tabindex="-1">Carrier Services <a class="header-anchor" href="#carrier-services" aria-label="Permalink to &quot;Carrier Services&quot;">​</a></h1><p>A <strong>CarrierService</strong> lets your Shopify app provide <strong>real-time shipping rates</strong> at checkout by responding to rate requests at a public <code>callback_url</code>.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://shopify.dev/docs/api/admin-rest/latest/resources/carrierservice" target="_blank" rel="noreferrer">CarrierService (REST Admin API)</a></li><li>Prefer <strong>GraphQL Admin API</strong> for new apps (REST legacy from Oct 2024)</li></ul><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><ol><li>App registers a carrier service with <code>name</code>, <code>callback_url</code>, and <code>service_discovery</code></li><li>At checkout Shopify <strong>POSTs</strong> cart origin, destination, items, and currency to your URL</li><li>Your server returns JSON <code>{ &quot;rates&quot;: [ … ] }</code> with <code>service_name</code>, <code>service_code</code>, <code>total_price</code> (subunits), <code>currency</code>, optional delivery dates</li><li>Empty <code>rates</code> + 2xx = “cannot ship”; 4xx/5xx triggers backup rates</li></ol><h2 id="access-requirements" tabindex="-1">Access requirements <a class="header-anchor" href="#access-requirements" aria-label="Permalink to &quot;Access requirements&quot;">​</a></h2><ul><li>App scope: <code>write_shipping</code></li><li>Store must be Advanced Shopify+, Shopify annual with carrier feature, or a <strong>development store</strong></li></ul><h2 id="rate-limits-caching" tabindex="-1">Rate limits &amp; caching <a class="header-anchor" href="#rate-limits-caching" aria-label="Permalink to &quot;Rate limits &amp; caching&quot;">​</a></h2><ul><li>Dynamic timeouts: <strong>10s / 5s / 3s</strong> based on requests per minute per shop-app pair</li><li>Shopify caches identical rate requests ~<strong>15 minutes</strong> (variant IDs, addresses, weights, box dimensions)</li></ul><h2 id="create-example" tabindex="-1">Create example <a class="header-anchor" href="#create-example" aria-label="Permalink to &quot;Create example&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;carrier_service&quot;:{&quot;name&quot;:&quot;My Rates&quot;,&quot;callback_url&quot;:&quot;https://shipping.example.com/rates&quot;,&quot;service_discovery&quot;:true}}&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://{shop}.myshopify.com/admin/api/2026-01/carrier_services.json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;X-Shopify-Access-Token: {token}&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span></span></code></pre></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./README.html">Shopify Dev</a></li><li><a href="./fulfilment-orders.html">Fulfillment Orders</a></li></ul>`,14)])])}const k=a(t,[["render",o]]);export{u as __pageData,k as default};
